// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

/**
 * @title TrustAgent
 * @notice Shardeum Mezame (Trust-Calendly) â€” meeting escrow in native SHM, AI oracle settlement,
 *         auto-refund after grace, and on-chain ReputationScore (`reputation` mapping).
 */
contract TrustAgent {
    address public owner;
    address public oracle;

    /// @notice Verifiable resume â€” cumulative ReputationScore per wallet.
    mapping(address => uint256) public reputation;

    uint256 public nextBookingId;

    /// @notice Grace after `meetingEnd` before `requestRefund` / `refundIfExpired` (time for AI audit).
    uint256 public constant REFUND_GRACE = 1 days;

    struct Booking {
        address company;
        address employee;
        uint256 amount;
        uint256 meetingEnd;
        bool settled;
    }

    mapping(uint256 => Booking) public bookings;

    bool private _entered;

    event Booked(
        uint256 indexed bookingId,
        address indexed company,
        address indexed employee,
        uint256 amount,
        uint256 meetingEnd
    );
    event OutcomeSettled(
        uint256 indexed bookingId,
        bool meetingSuccessful,
        address indexed beneficiary,
        uint256 amount,
        string reason
    );
    event ReputationIncreased(address indexed user, uint256 newTotal);
    event RefundedExpired(uint256 indexed bookingId, address indexed company, uint256 amount);

    error NotOwner();
    error NotOracle();
    error InvalidBooking();
    error AlreadySettled();
    error TooEarlyForRefund();
    error BadEmployee();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    modifier onlyOracle() {
        if (msg.sender != oracle) revert NotOracle();
        _;
    }

    modifier nonReentrant() {
        if (_entered) revert();
        _entered = true;
        _;
        _entered = false;
    }

    constructor(address oracle_) {
        owner = msg.sender;
        oracle = oracle_;
    }

    function setOracle(address o) external onlyOwner {
        oracle = o;
    }

    /// @notice Legacy name â€” same as `createMeeting`.
    function book(address employee, uint256 meetingEnd) external payable nonReentrant {
        _createMeeting(employee, meetingEnd);
    }

    /// @notice Trust-Calendly: company escrows native SHM to book an employee until meeting end.
    function createMeeting(address employee, uint256 meetingEnd) external payable nonReentrant {
        _createMeeting(employee, meetingEnd);
    }

    function _createMeeting(address employee, uint256 meetingEnd) internal {
        if (msg.value == 0) revert();
        if (employee == address(0) || employee == msg.sender) revert BadEmployee();
        if (meetingEnd <= block.timestamp) revert();

        uint256 id = ++nextBookingId;
        bookings[id] = Booking({
            company: msg.sender,
            employee: employee,
            amount: msg.value,
            meetingEnd: meetingEnd,
            settled: false
        });

        emit Booked(id, msg.sender, employee, msg.value, meetingEnd);
    }

    /// @notice AI oracle: success â†’ pay employee + ReputationScore; failure â†’ refund company.
    function executeOutcome(uint256 bookingId, bool meetingSuccessful, string calldata reason)
        external
        onlyOracle
        nonReentrant
    {
        _settle(bookingId, meetingSuccessful, reason);
    }

    /// @notice Release escrow to employee after verified success (oracle-only).
    function completeMeeting(uint256 bookingId, string calldata reason) external onlyOracle nonReentrant {
        _settle(bookingId, true, reason);
    }

    function _settle(uint256 bookingId, bool meetingSuccessful, string calldata reason) internal {
        Booking storage b = bookings[bookingId];
        if (b.company == address(0)) revert InvalidBooking();
        if (b.settled) revert AlreadySettled();

        b.settled = true;
        uint256 amt = b.amount;

        if (meetingSuccessful) {
            (bool ok, ) = payable(b.employee).call{value: amt}("");
            require(ok, "pay");
            unchecked {
                reputation[b.employee] += 10;
            }
            emit ReputationIncreased(b.employee, reputation[b.employee]);
            emit OutcomeSettled(bookingId, true, b.employee, amt, reason);
        } else {
            (bool ok, ) = payable(b.company).call{value: amt}("");
            require(ok, "refund");
            emit OutcomeSettled(bookingId, false, b.company, amt, reason);
        }
    }

    /// @notice Anyone may call after grace â€” auto-refund to company if still unsettled.
    function refundIfExpired(uint256 bookingId) external nonReentrant {
        _refundExpired(bookingId);
    }

    /// @notice Same as `refundIfExpired` â€” request refund after meeting + grace if AI never settled.
    function requestRefund(uint256 bookingId) external nonReentrant {
        _refundExpired(bookingId);
    }

    function _refundExpired(uint256 bookingId) internal {
        Booking storage b = bookings[bookingId];
        if (b.company == address(0)) revert InvalidBooking();
        if (b.settled) revert AlreadySettled();
        if (block.timestamp <= b.meetingEnd + REFUND_GRACE) revert TooEarlyForRefund();

        b.settled = true;
        uint256 amt = b.amount;
        (bool ok, ) = payable(b.company).call{value: amt}("");
        require(ok, "refund");

        emit RefundedExpired(bookingId, b.company, amt);
    }

    function increaseReputation(address user) external onlyOracle {
        unchecked {
            reputation[user] += 10;
        }
        emit ReputationIncreased(user, reputation[user]);
    }

    /// @notice Explicit getter for integrators (mirrors `reputation` mapping).
    function getReputationScore(address user) external view returns (uint256) {
        return reputation[user];
    }
}
